"use client";

import { useState, useTransition } from "react";
import { generateNamesAction } from "./actions";
import { Button } from "@workspace/ui/components/button";
import { Input } from "@workspace/ui/components/input";
import { Label } from "@workspace/ui/components/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@workspace/ui/components/card";
import { Slider } from "@workspace/ui/components/slider";

export default function Page() {
  const [length, setLength] = useState([5]);
  const [prefix, setPrefix] = useState("");
  const [suffix, setSuffix] = useState("");
  const [contains, setContains] = useState("");
  
  const [isPending, startTransition] = useTransition();
  const [data, setData] = useState<{ count: number, results: { name: string, meaning: string }[] } | null>(null);

  const handleGenerate = () => {
    startTransition(async () => {
      const res = await generateNamesAction(
        length[0] ?? 5, 
        prefix.toLowerCase(), 
        suffix.toLowerCase(), 
        contains.toLowerCase()
      );
      setData(res);
    });
  };

  return (
    <div className="flex min-h-screen flex-col items-center p-8 bg-background text-foreground">
      <div className="w-full max-w-5xl flex gap-8 flex-col md:flex-row">
        
        {/* Sidebar Configuration */}
        <div className="w-full md:w-80 flex-shrink-0">
          <Card>
            <CardHeader>
              <CardTitle>Wordloom</CardTitle>
              <CardDescription>Generate pronounceable names</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label>Target Length: {length[0]}</Label>
                </div>
                <Slider 
                  value={length} 
                  onValueChange={setLength} 
                  max={8} 
                  min={2} 
                  step={1} 
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="prefix">Prefix</Label>
                <Input 
                  id="prefix"
                  value={prefix}
                  onChange={(e) => setPrefix(e.target.value.replace(/[^a-zA-Z]/g, ''))}
                  placeholder="e.g. lu" 
                  maxLength={length[0]}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="suffix">Suffix</Label>
                <Input 
                  id="suffix"
                  value={suffix}
                  onChange={(e) => setSuffix(e.target.value.replace(/[^a-zA-Z]/g, ''))}
                  placeholder="e.g. id" 
                  maxLength={length[0]}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="contains">Contains</Label>
                <Input 
                  id="contains"
                  value={contains}
                  onChange={(e) => setContains(e.target.value.replace(/[^a-zA-Z]/g, ''))}
                  placeholder="e.g. min" 
                  maxLength={length[0]}
                />
              </div>

              <Button 
                onClick={handleGenerate} 
                disabled={isPending}
                className="w-full"
              >
                {isPending ? "Generating..." : "Generate Names"}
              </Button>
            </CardContent>
          </Card>
        </div>

        {/* Results Area */}
        <div className="flex-1 space-y-4">
          <div className="flex items-center justify-between border-b pb-4">
            <h2 className="text-xl font-semibold tracking-tight">Results</h2>
            {data && (
              <span className="text-sm text-muted-foreground">
                {data.count} result{data.count !== 1 ? 's' : ''}
              </span>
            )}
          </div>
          
          {!data ? (
            <div className="text-sm text-muted-foreground pt-4">
              Configure your parameters and click Generate to see results.
            </div>
          ) : data.count === 0 ? (
            <div className="text-sm text-muted-foreground pt-4">
              No results found. Try adjusting your parameters.
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {data.results.map((item, i) => (
                <div 
                  key={i} 
                  className="rounded-lg border bg-card text-card-foreground shadow-sm p-4 flex flex-col gap-2"
                >
                  <div className="flex items-center justify-between">
                    <span className="font-semibold text-lg">{item.name}</span>
                    {item.meaning && (
                      <span className="text-xs bg-muted text-muted-foreground px-2 py-1 rounded">
                        Wordnet
                      </span>
                    )}
                  </div>
                  {item.meaning && (
                    <p className="text-sm text-muted-foreground line-clamp-2">
                      {item.meaning}
                    </p>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
